        private readonly string[] permittedExtensions = { ".jpg", ".jpeg", ".png", ".gif", ".pdf", ".doc", ".docx", ".xls", ".xlsx", ".ppt", ".pptx" };
        private readonly string UploadsFolder = Path.Combine("wwwroot", "uploads");

        [HttpPost("upload")]
